import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { LedgerEntry } from '../../core/models';

interface StatementRow {
  entry: LedgerEntry;
  /** Positive for charges/late fees, negative for payments. */
  signedCents: number;
  /** Running account balance after this entry. */
  runningCents: number;
}

@Component({
  selector: 'app-statement',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './statement.component.html',
  styleUrl: './statement.component.css',
})
export class StatementComponent {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Ledger for lease l1, chronological (oldest first). */
  readonly entries = signal<LedgerEntry[]>([
    { id: 'e1', leaseId: 'l1', type: 'charge', amountCents: 120000, postedOn: '2026-05-01', period: '2026-05', note: 'Rent — May 2026' },
    { id: 'e2', leaseId: 'l1', type: 'payment', amountCents: 120000, postedOn: '2026-05-03', period: null, note: 'Payment received', receiptId: 'r1' },
    { id: 'e3', leaseId: 'l1', type: 'charge', amountCents: 120000, postedOn: '2026-06-01', period: '2026-06', note: 'Rent — June 2026' },
    { id: 'e4', leaseId: 'l1', type: 'payment', amountCents: 120000, postedOn: '2026-06-04', period: null, note: 'Payment received', receiptId: 'r2' },
    { id: 'e5', leaseId: 'l1', type: 'charge', amountCents: 120000, postedOn: '2026-07-01', period: '2026-07', note: 'Rent — July 2026' },
  ]);

  /** Rows with signed amount + running balance computed chronologically. */
  readonly rows = computed<StatementRow[]>(() => {
    let running = 0;
    return this.entries().map((entry) => {
      const signedCents = entry.type === 'payment' ? -entry.amountCents : entry.amountCents;
      running += signedCents;
      return { entry, signedCents, runningCents: running };
    });
  });

  /** Current outstanding balance = final running balance. */
  readonly balance = computed<number>(() => {
    const r = this.rows();
    return r.length ? r[r.length - 1].runningCents : 0;
  });

  badgeClass(type: LedgerEntry['type']): string {
    switch (type) {
      case 'payment':
        return 'badge-ok';
      case 'lateFee':
        return 'badge-danger';
      default:
        return 'badge-info';
    }
  }

  typeLabel(type: LedgerEntry['type']): string {
    switch (type) {
      case 'payment':
        return 'Payment';
      case 'lateFee':
        return 'Late fee';
      default:
        return 'Charge';
    }
  }
}
